FROM jsonb_to_recordset('[{"id": "cap-112-society-029", "exam_id": "cap", "subject_id": "sub-cap-social", "paper_id": "cap-112-society", "question_type": "single_choice", "question_text": "「距今六千多年前，此地區的人們觀察到，大約每隔365天，天狼星在拂曉的\n時候，和太陽同時位於東方的地平線上。因此他們定365天為一年，每年分為\n12個月，每月30天，年末加上5天。這種遵循太陽週期的曆法，依自然現象將\n一年分為『阿赫特』、『佩雷特』、『夏矛』三個季節，有別於同時期兩河流\n域的月亮週期曆法。」根據上文，「此地區」的發明最可能與下列何者有關？", "options": ["推算河川氾濫情形，掌握農業生產", "公民參與城邦事務，展現民主精神", "基於因果輪迴觀念，建立階級制度", "追尋宇宙創世真理，崇奉一神信仰"], "correct_answer": 0, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:41+00:00", "source_pdf_sha1": "388a2cade52f", "answer_pdf_sha1": "16ca7e0abba6", "flags": [], "parse_confidence": 1.0, "original_question_number": 29, "raw_text": "29. 「距今六千多年前，此地區的人們觀察到，大約每隔365天，天狼星在拂曉的\n    時候，和太陽同時位於東方的地平線上。因此他們定365天為一年，每年分為\n    12個月，每月30天，年末加上5天。這種遵循太陽週期的曆法，依自然現象將\n    一年分為『阿赫特』、『佩雷特』、『夏矛』三個季節，有別於同時期兩河流\n    域的月亮週期曆法。」根據上文，「此地區」的發明最可能與下列何者有關？\n    (A)推算河川氾濫情形，掌握農業生產 (B)公民參與城邦事務，展現民主精神\n    (C)基於因果輪迴觀念，建立階級制度 (D)追尋宇宙創世真理，崇奉一神信仰\n"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": null}, {"id": "cap-112-society-030", "exam_id": "cap", "subject_id": "sub-cap-social", "paper_id": "cap-112-society", "question_type": "single_choice", "question_text": "某中共領導人接見日本國會議員時提到：「戰後日本很快就發達起來，這經\n驗很值得中國學習。當然，別人的經驗照搬也不行，中國有中國的條件，日\n本有日本的條件。我們不但要引進發達國家的資金和技術，充分利用各國的\n好經驗，並且要把這種經驗與中國的實際情況結合起來。」上述談話最可能\n與下列何者有關？", "options": ["發起文化大革命，破除四舊", "推動農工大躍進，超英趕美", "沒收地主土地，分配給貧農", "實施改革開放，設經濟特區"], "correct_answer": 3, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:41+00:00", "source_pdf_sha1": "388a2cade52f", "answer_pdf_sha1": "16ca7e0abba6", "flags": [], "parse_confidence": 1.0, "original_question_number": 30, "raw_text": "30. 某中共領導人接見日本國會議員時提到：「戰後日本很快就發達起來，這經\n    驗很值得中國學習。當然，別人的經驗照搬也不行，中國有中國的條件，日\n    本有日本的條件。我們不但要引進發達國家的資金和技術，充分利用各國的\n    好經驗，並且要把這種經驗與中國的實際情況結合起來。」上述談話最可能\n    與下列何者有關？\n    (A)發起文化大革命，破除四舊 (B)推動農工大躍進，超英趕美\n    (C)沒收地主土地，分配給貧農 (D)實施改革開放，設經濟特區\n"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": null}, {"id": "cap-112-society-031", "exam_id": "cap", "subject_id": "sub-cap-social", "paper_id": "cap-112-society", "question_type": "single_choice", "question_text": "表(四)呈現甲國於兩次世界大戰中，         表(四)\n在歐洲戰場開始參戰與結束參戰的 甲國在歐洲      第一次   第二次\n原因。表中的「？」最適合填入下    戰場的情形  世界大戰  世界大戰\n列何者？                 開始  支援「斯拉 德國毀約攻", "options": ["美國投下原子彈，敵國投降    參戰的原因 夫兄弟」    打國土", "簽署《凡爾賽條約》，戰敗投降    結束 ？   德國投降", "國內共產政權成立，向同盟國議和 參戰的原因", "美國反對無限制潛艇政策，援助協約國"], "correct_answer": 2, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:41+00:00", "source_pdf_sha1": "388a2cade52f", "answer_pdf_sha1": "16ca7e0abba6", "flags": ["needs_image"], "parse_confidence": 0.85, "original_question_number": 31, "raw_text": "31. 表(四)呈現甲國於兩次世界大戰中，         表(四)\n    在歐洲戰場開始參戰與結束參戰的 甲國在歐洲      第一次   第二次\n    原因。表中的「？」最適合填入下    戰場的情形  世界大戰  世界大戰\n    列何者？                 開始  支援「斯拉 德國毀約攻\n    (A)美國投下原子彈，敵國投降    參戰的原因 夫兄弟」    打國土\n    (B)簽署《凡爾賽條約》，戰敗投降    結束\n                                ？   德國投降\n    (C)國內共產政權成立，向同盟國議和 參戰的原因\n    (D)美國反對無限制潛艇政策，援助協約國\n"}, "is_active": false, "auto_gradable": false, "difficulty": 3, "explanation": null}, {"id": "cap-112-society-032", "exam_id": "cap", "subject_id": "sub-cap-social", "paper_id": "cap-112-society", "question_type": "single_choice", "question_text": "西元前十ㄧ世紀周人滅商後，其勢力持續向東方擴展，由於周管轄的土地與人\n口在短時間內急速增加，為了天下的長治久安，因此周朝的統治者，設計出一\n套有效的政治制度管理各地。上述政治制度的內容，最可能是下列何者？", "options": ["在領土內設置郡、縣，官員由國君直接任免", "實施科舉制度，促進社會各階層人才的流動", "將百姓編入戶籍，並以法律規範人民的義務", "依據貴族的身分等級，授予土地與冊封爵位"], "correct_answer": 3, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:41+00:00", "source_pdf_sha1": "388a2cade52f", "answer_pdf_sha1": "16ca7e0abba6", "flags": [], "parse_confidence": 1.0, "original_question_number": 32, "raw_text": "32. 西元前十ㄧ世紀周人滅商後，其勢力持續向東方擴展，由於周管轄的土地與人\n    口在短時間內急速增加，為了天下的長治久安，因此周朝的統治者，設計出一\n    套有效的政治制度管理各地。上述政治制度的內容，最可能是下列何者？\n    (A)在領土內設置郡、縣，官員由國君直接任免\n    (B)實施科舉制度，促進社會各階層人才的流動\n    (C)將百姓編入戶籍，並以法律規範人民的義務\n    (D)依據貴族的身分等級，授予土地與冊封爵位\n"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": null}, {"id": "cap-112-society-033", "exam_id": "cap", "subject_id": "sub-cap-social", "paper_id": "cap-112-society", "question_type": "single_choice", "question_text": "「某位君主為了統治上的考量，需要招募許多能夠書寫的人才。一開始在他的\n國度中，竟然找不到太多有文化的人，這是因為西羅馬帝國滅亡後，城市生活\n逐漸消失，文化知識也幾乎被遺忘殆盡。因此這位君主特地聘請知名學者，來\n主持文化復興工作，諸如設立新學校、抄寫古羅馬的重要拉丁文著作，使拉丁\n文成為各地共通的文字系統。」上述學者的身分，最可能是下列何者？", "options": ["西元前五世紀的希臘哲學家", "西元八世紀的基督教教士", "西元十七世紀的歐洲天文學者", "西元十八世紀的啟蒙運動思想家"], "correct_answer": 1, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:41+00:00", "source_pdf_sha1": "388a2cade52f", "answer_pdf_sha1": "16ca7e0abba6", "flags": [], "parse_confidence": 1.0, "original_question_number": 33, "raw_text": "33. 「某位君主為了統治上的考量，需要招募許多能夠書寫的人才。一開始在他的\n    國度中，竟然找不到太多有文化的人，這是因為西羅馬帝國滅亡後，城市生活\n    逐漸消失，文化知識也幾乎被遺忘殆盡。因此這位君主特地聘請知名學者，來\n    主持文化復興工作，諸如設立新學校、抄寫古羅馬的重要拉丁文著作，使拉丁\n    文成為各地共通的文字系統。」上述學者的身分，最可能是下列何者？\n    (A)西元前五世紀的希臘哲學家  (B)西元八世紀的基督教教士\n    (C)西元十七世紀的歐洲天文學者 (D)西元十八世紀的啟蒙運動思想家\n\n\n"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": null}, {"id": "cap-112-society-034", "exam_id": "cap", "subject_id": "sub-cap-social", "paper_id": "cap-112-society", "question_type": "single_choice", "question_text": "在探討一國國內不同地區醫療資源差異時，通常會先觀察醫師人數和病床\n數，由相關數據與人口數的相對關係，可大致推論一個地區的醫療資源是否\n不足。表(五)是某國2018年四個地區關於人口與醫療資源的資料：\n表(五)\n地 人口總數 老年人口 醫師人數 平均每位醫師 病床數 平均每張病床\n區     (人)    比例(%)   (人)    負擔人數(人)   (張)   負擔人數(人)\n甲 2,562,738   19.50 9,719      263.7 19,951   128.5\n乙 2,272,459   13.26 3,824      594.3 11,988   189.6\n丙    673,309  19.42   881      764.3  3,204   210.1\n丁    322,836  17.95   820      393.7  4,073    79.3\n根據表中資料判斷，關於甲、乙、丙、丁四個地區的醫療資源，下列何項推\n論最適當？", "options": ["老年人口最多的地區醫療資源最為不足", "人口總數最少的地區醫療資源最為不足", "相對於其他地區，乙地區的醫療資源最為不足", "相對於其他地區，丙地區的醫療資源最為不足"], "correct_answer": 3, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:41+00:00", "source_pdf_sha1": "388a2cade52f", "answer_pdf_sha1": "16ca7e0abba6", "flags": ["needs_image"], "parse_confidence": 0.85, "original_question_number": 34, "raw_text": "34. 在探討一國國內不同地區醫療資源差異時，通常會先觀察醫師人數和病床\n    數，由相關數據與人口數的相對關係，可大致推論一個地區的醫療資源是否\n    不足。表(五)是某國2018年四個地區關於人口與醫療資源的資料：\n                           表(五)\n 地 人口總數 老年人口 醫師人數 平均每位醫師 病床數 平均每張病床\n 區     (人)    比例(%)   (人)    負擔人數(人)   (張)   負擔人數(人)\n 甲 2,562,738   19.50 9,719      263.7 19,951   128.5\n 乙 2,272,459   13.26 3,824      594.3 11,988   189.6\n 丙    673,309  19.42   881      764.3  3,204   210.1\n 丁    322,836  17.95   820      393.7  4,073    79.3\n    根據表中資料判斷，關於甲、乙、丙、丁四個地區的醫療資源，下列何項推\n    論最適當？\n    (A)老年人口最多的地區醫療資源最為不足\n    (B)人口總數最少的地區醫療資源最為不足\n    (C)相對於其他地區，乙地區的醫療資源最為不足\n    (D)相對於其他地區，丙地區的醫療資源最為不足\n"}, "is_active": false, "auto_gradable": false, "difficulty": 3, "explanation": null}, {"id": "cap-112-society-035", "exam_id": "cap", "subject_id": "sub-cap-social", "paper_id": "cap-112-society", "question_type": "single_choice", "question_text": "「飢餓行銷」是一種常見的行銷手法，指的是業者在短時間內利用各種管道\n宣傳大批民眾排隊購買的熱潮，營造該項商品都會很快被搶購一空的情況，\n透過媒體將商品炒作成為時下流行的話題，進而引起民眾的消費欲望。關於\n上述行銷手法對於消費市場的影響，下列敘述何者最適當？", "options": ["廠商間的競爭使消費者的選擇增加", "業者的行銷手法將提高市場競爭程度", "消費者受價格誘因影響而增加消費欲望", "民眾的購物意願受非金錢誘因影響而提高"], "correct_answer": 3, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:41+00:00", "source_pdf_sha1": "388a2cade52f", "answer_pdf_sha1": "16ca7e0abba6", "flags": [], "parse_confidence": 1.0, "original_question_number": 35, "raw_text": "35. 「飢餓行銷」是一種常見的行銷手法，指的是業者在短時間內利用各種管道\n    宣傳大批民眾排隊購買的熱潮，營造該項商品都會很快被搶購一空的情況，\n    透過媒體將商品炒作成為時下流行的話題，進而引起民眾的消費欲望。關於\n    上述行銷手法對於消費市場的影響，下列敘述何者最適當？\n    (A)廠商間的競爭使消費者的選擇增加\n    (B)業者的行銷手法將提高市場競爭程度\n    (C)消費者受價格誘因影響而增加消費欲望\n    (D)民眾的購物意願受非金錢誘因影響而提高\n"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": null}, {"id": "cap-112-society-036", "exam_id": "cap", "subject_id": "sub-cap-social", "paper_id": "cap-112-society", "question_type": "single_choice", "question_text": "若有人為了在選舉時讓支持的候選人當選，配合動員把戶籍遷移到非實際居\n住的行政區，企圖影響選舉結果，此種行為可能觸犯《刑法》，檢察官將代\n表國家主動起訴違法者。根據上述內容判斷，關於某位違法遷移戶籍者在接\n受偵查、審判的過程中，下列何種情況最可能出現？", "options": ["遭到落選者提起民事訴訟要求損害賠償", "在遭檢察官偵查的過程中度過18歲生日", "被查出是在投票日的六個月前遷移戶籍", "因為觸犯告訴乃論之罪而受到刑事處罰"], "correct_answer": 2, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:41+00:00", "source_pdf_sha1": "388a2cade52f", "answer_pdf_sha1": "16ca7e0abba6", "flags": [], "parse_confidence": 1.0, "original_question_number": 36, "raw_text": "36. 若有人為了在選舉時讓支持的候選人當選，配合動員把戶籍遷移到非實際居\n    住的行政區，企圖影響選舉結果，此種行為可能觸犯《刑法》，檢察官將代\n    表國家主動起訴違法者。根據上述內容判斷，關於某位違法遷移戶籍者在接\n    受偵查、審判的過程中，下列何種情況最可能出現？\n    (A)遭到落選者提起民事訴訟要求損害賠償\n    (B)在遭檢察官偵查的過程中度過18歲生日\n    (C)被查出是在投票日的六個月前遷移戶籍\n    (D)因為觸犯告訴乃論之罪而受到刑事處罰\n"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": null}, {"id": "cap-112-society-037", "exam_id": "cap", "subject_id": "sub-cap-social", "paper_id": "cap-112-society", "question_type": "single_choice", "question_text": "臺灣少子女化危機惡化的速度超乎想像，面對人口負成長的人口懸崖，有學\n者認為政府過往提出的相關政策已是緩不濟急，或許可以透過社會增加的方\n向，思考提高國民人數的對策。根據上述內容判斷，下列何項對策與該學者\n的意見最相符？", "options": ["提高外籍移工僱用人數", "鼓勵各國人才歸化入籍", "推動老人長期照護政策", "增加公立幼兒托育中心"], "correct_answer": 1, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:41+00:00", "source_pdf_sha1": "388a2cade52f", "answer_pdf_sha1": "16ca7e0abba6", "flags": [], "parse_confidence": 1.0, "original_question_number": 37, "raw_text": "37. 臺灣少子女化危機惡化的速度超乎想像，面對人口負成長的人口懸崖，有學\n    者認為政府過往提出的相關政策已是緩不濟急，或許可以透過社會增加的方\n    向，思考提高國民人數的對策。根據上述內容判斷，下列何項對策與該學者\n    的意見最相符？\n    (A)提高外籍移工僱用人數   (B)鼓勵各國人才歸化入籍\n    (C)推動老人長期照護政策   (D)增加公立幼兒托育中心\n"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": null}, {"id": "cap-112-society-038", "exam_id": "cap", "subject_id": "sub-cap-social", "paper_id": "cap-112-society", "question_type": "single_choice", "question_text": "表(六)為某作家的三部長篇          表(六)\n小說內容簡介，該作家藉此 著作       內 容 簡 介\n構築十九至二十世紀臺灣歷    刻畫多位臺灣青年在南洋戰場上被戰爭折\n甲\n史的發展過程。根據表中內    磨至精神崩潰，甚至喪生的悲慘命運。\n容判斷，這三部小說呈現的    敘述客家族群在臺灣中部山區生產樟腦，\n乙\n時代先後順序，最可能是下    為保衛家園參與武裝抗日的故事。\n列何者？            描繪臺灣人藉由參加文化協會、組織農民\n丙", "options": ["乙→甲→丙        運動，抵抗殖民統治的事蹟。", "丙→乙→甲", "丙→甲→乙", "乙→丙→甲"], "correct_answer": 3, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:41+00:00", "source_pdf_sha1": "388a2cade52f", "answer_pdf_sha1": "16ca7e0abba6", "flags": ["needs_image"], "parse_confidence": 0.85, "original_question_number": 38, "raw_text": "38. 表(六)為某作家的三部長篇          表(六)\n    小說內容簡介，該作家藉此 著作       內 容 簡 介\n    構築十九至二十世紀臺灣歷    刻畫多位臺灣青年在南洋戰場上被戰爭折\n                  甲\n    史的發展過程。根據表中內    磨至精